"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["6551"],{1108(e,n,i){i.r(n),i.d(n,{metadata:()=>a,default:()=>p,frontMatter:()=>s,contentTitle:()=>t,toc:()=>l,assets:()=>c});var a=JSON.parse('{"id":"Planets & Points/Uranus","title":"Uranus","description":"URANUS","source":"@site/docs/Planets & Points/Uranus.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Uranus","permalink":"/Planets & Points/Uranus","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Uranus.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Sun","permalink":"/Planets & Points/Sun"},"next":{"title":"Venus","permalink":"/Planets & Points/Venus"}}'),o=i(4848),r=i(8453);let s={},t,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.p,{children:"URANUS"}),"\n",(0,o.jsx)(n.p,{children:"Principle:"}),"\n",(0,o.jsx)(n.p,{children:"Suddenness, revolution, change."}),"\n",(0,o.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Peculiarity, independence, a love of freedom, independent action and ideas, enthusiasm for everything that is new or modern, agility or motility, good powers of perception, intuition allied with objective judgement, easy excitability. A sense of rhythm."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"An obstinate nature, lack of adaptability, rebellion, revolutionary tendencies, an excitable nature, impulsive actions, strong emotional tensions, passion for innovation, changeability of character."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"Rhythm, connections with the nervous system, with the meninges or membranes of the brain, with the pituitary gland (hypophysis cerebri) and with the spinal marrow."}),"\n",(0,o.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,o.jsx)(n.p,{children:"Reformers, inventors, technicians. \u2013 Rebels and revolutionaries."}),"\n",(0,o.jsx)(n.p,{children:"Positions in Houses and Signs:"}),"\n",(0,o.jsx)(n.p,{children:"I. Sudden outbursts of energy, quick comprehension, restlessness, ambition, fanatical fight for ideas. The urge to strive for reforms. \u2013 Stubbornness, blind zeal, violence. Dreamy enthusiasts and utopians."}),"\n",(0,o.jsx)(n.p,{children:'II. Resourcefulness in earning money, not seeking everyday or ordinary sources of money or means of livelihood, individual method of financing. \u2013 Speculation, risking all in one go, "putting all eggs in one basket", premature action leads to failure.'}),"\n",(0,o.jsx)(n.p,{children:"III. The tendency to take everything in jumps or a desultory manner in doing things, quick comprehension, circumspection, organisation, a convincing orator, scientific aspirations, original thoughts and methods. \u2013 A restless nature, the tendency to scatter one's energies."}),"\n",(0,o.jsx)(n.p,{children:"IV. Intuition, a quick change of ideas, wanderlust, the longing for faraway places, the inclination to associate oneself with peculiar or strange people, the urge to break away from one's native country or parental home, rebelliousness."}),"\n",(0,o.jsx)(n.p,{children:"V. The spirit of enterprise, boldness, determination, the love of freedom, the desire to gamble or to speculate. \u2013 Love of adventure, wastefulness, licentiousness."}),"\n",(0,o.jsx)(n.p,{children:"VI. The urge to reform, a good intellect, skill, good comprehensive powers, one's own methods of working, the selection of unusual vocations or professions. \u2013 Foolish aspirations, teamwork made difficult by misplaced criticism or tactless frankness."}),"\n",(0,o.jsx)(n.p,{children:"VII. Inspiration, power of empathy, artistic talent, creativity, the desire to carry out reforms in the interest of the public, peculiar views on marriage. \u2013 A lack of adaptability, irritability, a trouble-maker."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Responsiveness, energetic or forceful character fearlessly facing the struggle with destiny, a sudden realisation of ideas, ruthlessness, the tendency to get oneself and others into danger."}),"\n",(0,o.jsx)(n.p,{children:"IX. The desire to carry through reforms in accordance with religion or outlook on life, fanaticism, far-reaching aims. \u2013 A love of adventure, a tenacious clinging to strange ideas, restlessness, the fight against traditional and conventional forms."}),"\n",(0,o.jsx)(n.p,{children:"X. Concentrated energy, extraordinary aims in life which are pursued with zeal and ambition, resoluteness, technical abilities and interests. \u2013 An almost fanatical concentration upon certain aims."}),"\n",(0,o.jsx)(n.p,{children:"XI. A knowledge of human nature, aspiring to make changes, collective and cooperative work, organising talent, manifold aspirations, a progressive mind or spirit. \u2013 A trouble-maker, a rebellious behaviour, the tendency to exaggerate, to magnify everything."}),"\n",(0,o.jsx)(n.p,{children:"XII. An inclination to mysticism, mysterious aspirations, subconscious forces. \u2013 Secretive behaviour, the state of being misunderstood or of not being understood at all, reverie or revelling ecstasy."}),"\n",(0,o.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,o.jsx)(n.p,{children:"URAN"}),"\n",(0,o.jsx)(n.p,{children:"Zasada:"}),"\n",(0,o.jsx)(n.p,{children:"Nagle liczno\u015B\u0107 (nag\u0142o\u015B\u0107), rewolucja, zmiana."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,o.jsxs)(n.ul,{children:["\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Osobliwo\u015B\u0107, niezale\u017Cno\u015B\u0107, zami\u0142owanie do wolno\u015Bci, niezale\u017Cne dzia\u0142anie i pomys\u0142y, entuzjazm dla wszystkiego, co nowe lub nowoczesne, zwinno\u015B\u0107 lub ruchliwo\u015B\u0107, dobra zdolno\u015B\u0107 percepcji, intuicja po\u0142\u0105czona z obiektywnym os\u0105dem, \u0142atwa pobudliwo\u015B\u0107. Zmys\u0142 rytmu."}),"\n"]}),"\n",(0,o.jsxs)(n.li,{children:["\n",(0,o.jsx)(n.p,{children:"Uparty charakter, brak zdolno\u015Bci adaptacji, bunt, tendencje rewolucyjne, pobudliwa natura, impulsywne dzia\u0142ania, silne napi\u0119cia emocjonalne, pasja do innowacji, zmienno\u015B\u0107 charakteru."}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Rytm, powi\u0105zania z uk\u0142adem nerwowym, z oponami m\xf3zgowymi lub b\u0142onami m\xf3zgu, z przysadk\u0105 m\xf3zgow\u0105 (hypophysis cerebri) i z rdzeniem kr\u0119gowym."}),"\n",(0,o.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,o.jsx)(n.p,{children:"Reformatorzy, wynalazcy, technicy. \u2013 Buntownicy i rewolucjoni\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"Pozycje w domach i znakach:"}),"\n",(0,o.jsx)(n.p,{children:"I. Nag\u0142e wybuchy energii, szybkie pojmowanie, niepok\xf3j, ambicja, fanatyczna walka o idee. Pragnienie d\u0105\u017Cenia do reform. \u2013 Uparto\u015B\u0107, \u015Blepa gorliwo\u015B\u0107, przemoc. Marzyciele-entyuzja\u015Bci i utopi\u015Bci."}),"\n",(0,o.jsx)(n.p,{children:"II. Zaradno\u015B\u0107 w zarabianiu pieni\u0119dzy, nieszukanie codziennych lub zwyczajnych \u017Ar\xf3de\u0142 pieni\u0119dzy lub \u015Brodk\xf3w do \u017Cycia, indywidualna metoda finansowania. \u2013 Spekulacja, ryzykowanie wszystkiego naraz, \u201Estawianie wszystkiego na jedn\u0105 kart\u0119\u201D (wk\u0142adanie wszystkich jajek do jednego koszyka), przedwczesne dzia\u0142anie prowadzi do niepowodzenia."}),"\n",(0,o.jsx)(n.p,{children:"III. Tendencja do brania wszystkiego skokowo lub chaotycznego sposobu robienia rzeczy, szybkie pojmowanie, pow\u015Bci\u0105gliwo\u015B\u0107 (ostro\u017Cno\u015B\u0107), organizacja, przekonuj\u0105cy m\xf3wca, aspiracje naukowe, oryginalne my\u015Bli i metody. \u2013 Niespokojna natura, tendencja do rozpraszania swoich energii."}),"\n",(0,o.jsx)(n.p,{children:"IV. Intuicja, szybka zmiana pomys\u0142\xf3w, zami\u0142owanie do w\u0119dr\xf3wek (wanderlust), t\u0119sknota za dalekimi miejscami, sk\u0142onno\u015B\u0107 do zadawania si\u0119 z osobliwymi lub dziwnymi lud\u017Ami, pragnienie oderwania si\u0119 od ojczystego kraju lub domu rodzinnego, buntowniczo\u015B\u0107."}),"\n",(0,o.jsx)(n.p,{children:"V. Duch przedsi\u0119biorczo\u015Bci, \u015Bmia\u0142o\u015B\u0107, determinacja, zami\u0142owanie do wolno\u015Bci, pragnienie hazardu lub spekulacji. \u2013 Zami\u0142owanie do przyg\xf3d, rozrzutno\u015B\u0107, rozpusta."}),"\n",(0,o.jsx)(n.p,{children:"VI. Pragnienie reform, dobry intelekt, umiej\u0119tno\u015Bci, dobra zdolno\u015B\u0107 pojmowania, w\u0142asne metody pracy, wyb\xf3r nietypowych zaj\u0119\u0107 lub profesji. \u2013 Niedorzeczne aspiracje, praca zespo\u0142owa utrudniona przez nietrafion\u0105 krytyk\u0119 lub nietaktown\u0105 szczero\u015B\u0107."}),"\n",(0,o.jsx)(n.p,{children:"VII. Inspiracja, si\u0142a empatii, talent artystyczny, kreatywno\u015B\u0107, pragnienie przeprowadzania reform w interesie publicznym, osobliwe pogl\u0105dy na ma\u0142\u017Ce\u0144stwo. \u2013 Brak zdolno\u015Bci adaptacji, dra\u017Cliwo\u015B\u0107, m\u0105ciciel (awanturnik)."}),"\n",(0,o.jsx)(n.p,{children:"VIII. Reaktywno\u015B\u0107 (wra\u017Cliwo\u015B\u0107 na bod\u017Ace), energiczny lub silny charakter bez l\u0119ku stawiaj\u0105cy czo\u0142a walce z przeznaczeniem, nag\u0142a realizacja pomys\u0142\xf3w, bezwzgl\u0119dno\u015B\u0107, tendencja do wprowadzania siebie i innych w niebezpiecze\u0144stwo."}),"\n",(0,o.jsx)(n.p,{children:"IX. Pragnienie przeprowadzania reform w zgodzie z religi\u0105 lub \u015Bwiatopogl\u0105dem, fanatyzm, dalekosi\u0119\u017Cne cele. \u2013 Zami\u0142owanie do przyg\xf3d, nieust\u0119pliwe trzymanie si\u0119 dziwnych pomys\u0142\xf3w, niepok\xf3j, walka z tradycyjnymi i konwencjonalnymi formami."}),"\n",(0,o.jsx)(n.p,{children:"X. Skoncentrowana energia, niezwyk\u0142e cele w \u017Cyciu, kt\xf3re s\u0105 realizowane z gorliwo\u015Bci\u0105 i ambicj\u0105, stanowczo\u015B\u0107, zdolno\u015Bci i zainteresowania techniczne. \u2013 Niemal fanatyczna koncentracja na okre\u015Blonych celach."}),"\n",(0,o.jsx)(n.p,{children:"XI. Znajomo\u015B\u0107 natury ludzkiej, d\u0105\u017Cenie do wprowadzania zmian, praca zbiorowa i zespo\u0142owa, talent organizacyjny, r\xf3\u017Cnorodne aspiracje, post\u0119powy umys\u0142 lub duch. \u2013 M\u0105ciciel, buntownicze zachowanie, tendencja do przesadzania, wyolbrzymiania wszystkiego."}),"\n",(0,o.jsx)(n.p,{children:"XII. Sk\u0142onno\u015B\u0107 do mistycyzmu, tajemnicze aspiracje, si\u0142y pod\u015Bwiadomo\u015Bci. \u2013 Skryte zachowanie, stan bycia niezrozumianym lub niebycia rozumianym w og\xf3le, marzycielstwo lub upajaj\u0105ca ekstaza."})]})}function p(e={}){let{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>s,x:()=>t});var a=i(6540);let o={},r=a.createContext(o);function s(e){let n=a.useContext(r);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function t(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),a.createElement(r.Provider,{value:n},e.children)}}}]);